// V18.0: 手动触发=昨天(23:59收盘), 定时触发=今天(当日收盘)
const row = $input.first().json;

// 检测触发方式: Webhook=手动, Schedule=定时
let isManual = false;
try {
  const d = $('手动触发Webhook').all();
  if (d && d.length > 0) isManual = true;
} catch(e) { /* Schedule触发时无Webhook数据 */ }

const snapshotDate = isManual ? row.yesterday_date : row.today_date;
return { json: {
  snapshot_date: snapshotDate,
  trigger_type: isManual ? 'manual' : 'cron'
} };

// V16.2: 修复批量写入PG丢失SQL问题
// 原因: '清除当天旧快照'节点输出覆盖了原始批次SQL数据
// 方案: 将DELETE合并到第一个INSERT批次, 跳过独立DELETE节点
const allInput = $input.all().map(r => r.json);
const filteredRows = allInput.filter(r => r.item_code && String(r.item_code).trim() !== '');

// 按item_code+whs_code+bin_code+batch_number去重，SAP JOIN可能产生重复行
const seen = new Set();
const rawRows = filteredRows.filter(r => {
  const key = String(r.item_code) + '|' + String(r.whs_code||'') + '|' + String(r.bin_code||'') + '|' + String(r.batch_number||'');
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (rawRows.length === 0) {
  return [{ json: { _skip: true, success: true, snapshot_date: '', total_rows: 0, max_sap_update_date: '', message: 'SAP无库存变动，保留旧快照' } }];
}

// V18.0: 从上游获取快照日期 (手动=昨天, 定时=今天)
const snapshotDate = $('准备参数').first().json.snapshot_date;

// V17.0: 全量模式不再追踪 SAP UpdateDate
const maxSapDate = '';

// 生成INSERT SQL批次
const batchSize = 500;
const batches = [];
const esc = (v) => { if(v===null||v===undefined) return 'NULL'; let s=String(v).substring(0,500); s=s.replace(/�/g,''); s=s.replace(/\\/g,'\\\\').replace(/'/g,"''"); return "'"+s+"'"; };
const num = (v) => v===null||v===undefined ? 0 : Number(v)||0;
const dateFmt = (v) => { if(!v) return 'NULL'; const s=String(v); const m=s.match(/^(\d{4}-\d{2}-\d{2})/); return m ? "'"+m[1]+"'" : 'NULL'; };

const cols = 'company_code,snapshot_date,item_code,item_name,foreign_name,item_group,uom,whs_code,whs_name,bin_code,bin_enabled,batch_managed,batch_number,mfr_batch,lot_number,mfr_date,exp_date,in_date,on_hand,bin_qty,batch_qty,bin_max_level,avg_price,stock_value,total_on_hand,committed_qty,ordered_qty,synced_at';

for (let i = 0; i < rawRows.length; i += batchSize) {
  const batch = rawRows.slice(i, i + batchSize);
  const values = batch.map(r => {
    return `(${esc($env.DP_COMPANY_CODE)},${esc(snapshotDate)},${esc(r.item_code)},${esc(r.item_name)},${esc(r.foreign_name)},${esc(r.item_group)},${esc(r.uom)},${esc(r.whs_code)},${esc(r.whs_name)},${esc(r.bin_code)},${esc(r.bin_enabled)},${esc(r.batch_managed)},${esc(r.batch_number)},${esc(r.mfr_batch)},${esc(r.lot_number)},${dateFmt(r.mfr_date)},${dateFmt(r.exp_date)},${dateFmt(r.in_date)},${num(r.on_hand)},${num(r.bin_qty)},${num(r.batch_qty)},${num(r.bin_max_level)},${num(r.avg_price)},${num(r.stock_value)},${num(r.total_on_hand)},${num(r.committed_qty)},${num(r.ordered_qty)},NOW())`;
  }).join(',\n');

  let sql;
  if (i === 0) {
    // 第一个批次: 先DELETE所有旧快照再INSERT (保留最新一份即可，防止历史累积导致wf08 SUM膨胀)
    sql = `DELETE FROM wms.wms_stock_snapshot WHERE company_code = ${esc($env.DP_COMPANY_CODE)};\nINSERT INTO wms.wms_stock_snapshot (${cols}) VALUES ${values}`;
  } else {
    sql = `INSERT INTO wms.wms_stock_snapshot (${cols}) VALUES ${values}`;
  }

  batches.push({ json: {
    _skip: false,
    sql: sql,
    batch_num: Math.floor(i/batchSize)+1,
    _snapshot_date: snapshotDate,
    _max_sap_update_date: maxSapDate,
    _total_rows: rawRows.length
  } });
}
return batches;

// V16.2: 汇总结果，从转换+生成SQL节点获取元数据 (不依赖上游Postgres输出)
const firstBatch = $('转换+生成SQL').first().json;
return { json: {
  success: true,
  snapshot_date: firstBatch._snapshot_date || '',
  total_rows: firstBatch._total_rows || 0,
  max_sap_update_date: firstBatch._max_sap_update_date || '',
  message: '库存快照同步完成: SAP ' + (firstBatch._total_rows || 0) + '行 写入PG'
} };
